 18	import {
 19	  ListPageBody,
 20	  ListPageFilter,
 21	  useListPageFilter,
 22	  VirtualizedTable,
 23	} from '@openshift-console/dynamic-plugin-sdk';
 24	import { Flex, FlexItem, PageSection, PageSectionVariants } from '@patternfly/react-core';
 25	
 26	import DiskRow from './components/DiskRow';
 27	import useDiskColumns from './hooks/useDiskColumns';
 28	import useDisksFilters from './hooks/useDisksFilters';
 29	import useWizardDisksTableData from './hooks/useWizardDisksTableData';
 30	
 31	const WizardDisksTab: WizardTab = ({ tabsData, updateTabsData, updateVM, vm }) => {
 32	  const { createModal } = useModal();
 33	  const columns = useDiskColumns();
 34	  const [disks, disksLoaded] = useWizardDisksTableData(vm);
 35	  const filters = useDisksFilters();
 36	  const [data, filteredData, onFilterChange] = useListPageFilter(disks, filters);
 37	  const { decodedRegistryCredentials, updateRegistryCredentials } = useRegistryCredentials();
 38	
 39	  const handleSubmit = (newVM: V1VirtualMachine, diskFormState: V1DiskFormState) => {
 40	    const { registryCredentials } = diskFormState;
 41	    !isEmpty(registryCredentials) && updateRegistryCredentials(registryCredentials);
 42	    return updateVM(newVM);
 43	  };
 44	
 45	  const defaultFormValues: DefaultFormValues = { registryCredentials: decodedRegistryCredentials };
 46	
 47	  return (
 48	    <PageSection variant={PageSectionVariants.light}>
 49	      <ListPageBody>
 50	        <SidebarEditor
 51	          onResourceUpdate={(newVM) => updateVM(newVM)}
 52	          pathsToHighlight={PATHS_TO_HIGHLIGHT.DISKS_TAB}
 53	          resource={vm}
 54	        >
 55	          <DiskSourceSelect
 56	            onSelect={(diskSource: SourceTypes) => {
 57	              return createModal(({ isOpen, onClose }) => (
 58	                <DiskModal
 59	                  onUploadedDataVolume={(dataVolume) =>
 60	                    updateTabsData((draft) => {
 61	                      ensurePath(draft, 'disks.dataVolumesToAddOwnerRef');
 62	                      if (draft.disks) {
 63	                        draft.disks.dataVolumesToAddOwnerRef = [
 64	                          ...(tabsData?.disks?.dataVolumesToAddOwnerRef || []),
 65	                          dataVolume,
 66	                        ];
 67	                      }
 68	                    })
 69	                  }
 70	                  createDiskSource={diskSource}
 71	                  defaultFormValues={defaultFormValues}
 72	                  isOpen={isOpen}
 73	                  onClose={onClose}
 74	                  onSubmit={handleSubmit}
 75	                  vm={vm}
 76	                />
 77	              ));
 78	            }}
 79	            className="list-page-create-button-margin"
 80	          />
 81	          <Flex>
 82	            <FlexItem>
 83	              <ListPageFilter
 84	                data={data}
 85	                hideLabelFilter
 86	                loaded={disksLoaded}
 87	                onFilterChange={onFilterChange}
 88	                rowFilters={filters}
 89	              />
 90	            </FlexItem>
 91	            <FlexItem>
 92	              <WindowsDrivers updateVM={updateVM} vm={vm} />
 93	            </FlexItem>
 94	          </Flex>
 95	          <VirtualizedTable
 96	            columns={columns}
 97	            data={filteredData}
 98	            loaded={disksLoaded}
 99	            loadError={undefined}
100	            Row={DiskRow}
101	            unfilteredData={data}
102	          />
103	        </SidebarEditor>
104	      </ListPageBody>
105	    </PageSection>
106	  );
107	};
108	
109	export default WizardDisksTab;

